#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        long long *pref = (long long*)calloc(N+1, sizeof(long long));
        for(int i=1;i<=N;i++){
            long long x; scanf("%lld", &x);
            pref[i] = pref[i-1] ^ x;
        }
        int lo=1, hi=N, ans=-1;
        while(lo<=hi){
            int mid = (lo+hi)/2;
            int ok=0;
            for(int i=0;i+mid<=N;i++){
                long long xr = pref[i+mid] ^ pref[i];
                if(xr >= K){ ok=1; break; }
            }
            if(ok){ ans=mid; hi=mid-1; }
            else lo=mid+1;
        }
        printf("%d\n", ans);
        free(pref);
    }
    return 0;
}

