import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        pref = [0]*(N+1)
        for i in range(1, N+1):
            x = int(next(it))
            pref[i] = pref[i-1] ^ x
        lo, hi, ans = 1, N, -1
        while lo <= hi:
            mid = (lo+hi)//2
            ok = False
            for i in range(0, N-mid+1):
                if (pref[i+mid] ^ pref[i]) >= K:
                    ok = True
                    break
            if ok:
                ans = mid
                hi = mid-1
            else:
                lo = mid+1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

